ValidationRule.errorConditionFormula:
AND(
    /* 1. Global Switch Check */
    NOT($Setup.RES_Config_Switch__c.RES_Validation_Rules_Off__c),

    /* 2. Target specific Record Types */
    OR(
        $RecordType.DeveloperName ="RES_Residential_Single_Buyer",
        $RecordType.DeveloperName = "RES_Residential_Multi_Buyer"
    ),

    /* 3. Do not fire on initial creation */
    NOT(ISNEW()),

    /* 4. Only fire if the previous stage was 'Closed Won' */
    ISPICKVAL(PRIORVALUE(StageName), "Closed Won"),

    /* 5. Bypass System Admin Profile */
    $Profile.Name <> "System Administrator",

    /* 6. Bypass specific Operations Roles */
    NOT(
        OR(
            $UserRole.DeveloperName = "RES_Sales_Operations_Executive_Director",
            $UserRole.DeveloperName = "RES_Contract_Amendments_Operations_Specialist",
            $UserRole.DeveloperName = "RES_External_Sales_Operations_Operations_Senior_Manager",
            $UserRole.DeveloperName = "RES_External_Sales_Operations_Operations_Specialist",
            $UserRole.DeveloperName = "RES_Internal_Sales_Contracts_Operations_Senior_Manager",
            $UserRole.DeveloperName = "RES_Internal_Sales_Operations_Operations_Manager",
            $UserRole.DeveloperName = "RES_Internal_Sales_Operations_Operations_Specialist",
            $UserRole.DeveloperName = "RES_Operational_Excellence_Operations_Manager",
            $UserRole.DeveloperName = "RES_Operational_Excellence_Operations_Specialist"
        )
    )
)
